"use client"
import { useEffect, useState } from "react"
import { supabase, isConfigured } from "../app/lib/supabase"
import { Plus, Trash2, Film, Tv, Drama, AlertCircle } from "lucide-react"

type WatchCategory = "Movies" | "TV Shows" | "Anime"

export default function Movies() {
  const [movies, setMovies] = useState<string[]>([])
  const [newMovie, setNewMovie] = useState("")
  const [category, setCategory] = useState<WatchCategory>("Movies")

  useEffect(() => {
    if (!supabase || !isConfigured) return

    const channel = supabase
      .channel("movies")
      .on("postgres_changes", { event: "*", schema: "public", table: "widgets", filter: "id=eq.movies" }, (payload: any) => {
        const allMovies = [
          ...(payload.new?.movies || []).map((m: string) => `[Movies] ${m}`),
          ...(payload.new?.tvshows || []).map((t: string) => `[TV Shows] ${t}`),
          ...(payload.new?.anime || []).map((a: string) => `[Anime] ${a}`),
        ]
        setMovies(allMovies)
      })
      .subscribe()

    // Initial fetch
    supabase
      .from("widgets")
      .select("movies,tvshows,anime")
      .eq("id", "movies")
      .single()
      .then(({ data }: any) => {
        const allMovies = [
          ...(data?.movies || []).map((m: string) => `[Movies] ${m}`),
          ...(data?.tvshows || []).map((t: string) => `[TV Shows] ${t}`),
          ...(data?.anime || []).map((a: string) => `[Anime] ${a}`),
        ]
        setMovies(allMovies)
      })

    return () => {
      supabase!.removeChannel(channel)
    }
  }, [])

  const addMovie = async () => {
    if (!newMovie.trim()) return
    if (!supabase) {
      setMovies([...movies, `[${category}] ${newMovie}`])
      setNewMovie("")
      return
    }
    const fieldName = category === "Movies" ? "movies" : category === "TV Shows" ? "tvshows" : "anime"
    const { data } = await supabase.from("widgets").select(fieldName).eq("id", "movies").single()
    const currentList = (data as any)?.[fieldName] || []
    await supabase.from("widgets").update({ [fieldName]: [...currentList, newMovie] }).eq("id", "movies")
    setNewMovie("")
  }

  const removeMovie = async (movie: string) => {
    const { category: movieCat, title } = parseMovie(movie)
    const fieldName = movieCat === "Movies" ? "movies" : movieCat === "TV Shows" ? "tvshows" : "anime"
    if (supabase) {
      const { data } = await supabase.from("widgets").select(fieldName).eq("id", "movies").single()
      const currentList = (data as any)?.[fieldName] || []
      await supabase.from("widgets").update({ [fieldName]: currentList.filter((m: string) => m !== title) }).eq("id", "movies")
    } else {
      setMovies(movies.filter((m) => m !== movie))
    }
  }

  const parseMovie = (movie: string) => {
    const match = movie.match(/^\[(.*?)\] (.*)/)
    if (match) {
      return { category: match[1] as WatchCategory, title: match[2] }
    }
    return { category: "Movies" as WatchCategory, title: movie }
  }

  const getCategoryIcon = (cat: WatchCategory) => {
    switch (cat) {
      case "Movies":
        return <Film className="w-4 h-4 text-primary" />
      case "TV Shows":
        return <Tv className="w-4 h-4 text-primary" />
      case "Anime":
        return <Drama className="w-4 h-4 text-primary" />
    }
  }

  if (!isConfigured) {
    return (
      <div className="space-y-4">
        <div className="flex items-start gap-3 p-4 bg-yellow-50 border border-yellow-200 rounded-xl">
          <AlertCircle className="w-5 h-5 text-yellow-600 flex-shrink-0 mt-0.5" />
          <div className="flex-1">
            <p className="text-sm font-medium text-yellow-800 mb-1">Supabase Not Configured</p>
            <p className="text-xs text-yellow-700">
              Please add your Supabase environment variables in the Vars section of the sidebar.
            </p>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2 flex-wrap">
        <button
          onClick={() => setCategory("Movies")}
          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
            category === "Movies"
              ? "bg-primary text-primary-foreground"
              : "bg-muted hover:bg-muted/80 text-muted-foreground"
          }`}
        >
          <Film className="w-3.5 h-3.5" />
          Movies
        </button>
        <button
          onClick={() => setCategory("TV Shows")}
          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
            category === "TV Shows"
              ? "bg-primary text-primary-foreground"
              : "bg-muted hover:bg-muted/80 text-muted-foreground"
          }`}
        >
          <Tv className="w-3.5 h-3.5" />
          TV Shows
        </button>
        <button
          onClick={() => setCategory("Anime")}
          className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
            category === "Anime"
              ? "bg-primary text-primary-foreground"
              : "bg-muted hover:bg-muted/80 text-muted-foreground"
          }`}
        >
          <Drama className="w-3.5 h-3.5" />
          Anime
        </button>
      </div>

      {/* Add Movie Input */}
      <div className="flex gap-2">
        <input
          type="text"
          value={newMovie}
          onChange={(e) => setNewMovie(e.target.value)}
          onKeyPress={(e) => e.key === "Enter" && addMovie()}
          placeholder={`Add ${category.toLowerCase()}...`}
          className="flex-1 px-4 py-2.5 bg-input border border-border rounded-xl text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary transition-all"
        />
        <button
          onClick={addMovie}
          className="px-4 py-2.5 bg-primary text-primary-foreground rounded-xl hover:bg-primary/90 transition-colors flex-shrink-0"
        >
          <Plus className="w-5 h-5" />
        </button>
      </div>

      {/* Movies List */}
      {movies.length > 0 ? (
        <div className="space-y-2 max-h-72 overflow-y-auto pr-2">
          {movies.map((movie, i) => {
            const { category: movieCat, title } = parseMovie(movie)
            return (
              <div
                key={i}
                className="flex items-center gap-3 p-3 bg-muted/50 rounded-xl hover:bg-muted transition-colors group"
              >
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-primary/20 to-secondary/20 flex items-center justify-center flex-shrink-0">
                  {getCategoryIcon(movieCat)}
                </div>
                <span className="flex-1 text-sm text-foreground">{title}</span>
                <button
                  onClick={() => removeMovie(movie)}
                  className="w-7 h-7 rounded-lg bg-red-100 text-red-600 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0"
                >
                  <Trash2 className="w-4 h-4" />
                </button>
              </div>
            )
          })}
        </div>
      ) : (
        <div className="text-center py-8">
          <Film className="w-12 h-12 text-muted-foreground/50 mx-auto mb-2" />
          <p className="text-sm text-muted-foreground">No items added yet</p>
        </div>
      )}
    </div>
  )
}
